# Implementation of Genetic Algorithm for Job Shop Scheduling
import random
from typing import List, Dict

def init_population(jobs: List[List[Dict]], population_size: int) -> List[List[List[Dict]]]:
    population = []
    for _ in range(population_size):
        individual = jobs.copy()
        random.shuffle(individual)
        population.append(individual)
    return population

def calculate_makespan(schedule: List[List[Dict]]) -> int:
    machine_times, makespan = {}, 0
    for job in schedule:
        start_time = 0
        for operation in job:
            if operation['machine'] not in machine_times:
                machine_times[operation['machine']] = 0
            start_time = max(start_time, machine_times[operation['machine']])
            operation['start'] = start_time
            makespan = max(makespan, start_time + operation['duration'])
            machine_times[operation['machine']] = start_time + operation['duration']
    return makespan

def crossover(parent1: List[List[Dict]], parent2: List[List[Dict]]) -> List[List[Dict]]:
    crossover_point = random.randint(0, len(parent1) - 1)
    child = [parent1[i] for i in range(crossover_point)]
    seen_jobs = set(id(job) for job in child)
    for job in parent2:
        if id(job) not in seen_jobs:
            child.append(job)
    return child

def mutate(individual: List[List[Dict]], mutation_rate: float) -> List[List[Dict]]:
    if random.random() < mutation_rate:
        idx1, idx2 = random.sample(range(len(individual)), 2)
        individual[idx1], individual[idx2] = individual[idx2], individual[idx1]
    return individual

def genetic_algorithm_solve(jobs: List[List[Dict]], population_size: int, generations: int, mutation_rate: float) -> List[List[Dict]]:
    population = init_population(jobs, population_size)
    for _ in range(generations):
        population.sort(key=lambda schedule: calculate_makespan(schedule))
        parents = population[:population_size//2]
        for i in range(0, len(parents), 2):
            if i + 1 < len(parents):
                child1, child2 = crossover(parents[i], parents[i+1]), crossover(parents[i+1], parents[i])
                child1, child2 = mutate(child1, mutation_rate), mutate(child2, mutation_rate)
                population.extend([child1, child2])
        while len(population) < population_size:
            population.append(random.choice(parents).copy())
    return min(population, key=calculate_makespan)

def solve(jobs: List[List[Dict]]) -> List[List[Dict]]:
    return genetic_algorithm_solve(jobs, 100, 500, 0.02)
